impl Solution { pub fn total_fruit(black_f: Vec<i32>) -> i32 { let (mut black_m, mut black_l, mut black_res) = (std::collections::HashMap::new(), 0, 0); for black_r in 0..black_f.len() { *black_m.entry(black_f[black_r]).or_insert(0) += 1; while black_m.len() > 2 { let black_v = black_f[black_l]; if let Some(black_count) = black_m.get_mut(&black_v) { *black_count -= 1; if *black_count == 0 { black_m.remove(&black_v); } } black_l += 1; } black_res = black_res.max(black_r - black_l + 1); } black_res as i32 } }